import axios from 'axios';

// ===================================================================================
// IMPORTANT: DEPLOYMENT CONFIGURATION
// ===================================================================================
// When you deploy your backend, you MUST replace the placeholder URL below with
// your actual live server URL (e.g., from Render, Vercel, etc.).
// ===================================================================================
const LIVE_BACKEND_URL = 'https://your-backend-url.onrender.com'; // <-- PASTE YOUR RENDER URL HERE

// This setup allows your app to work seamlessly in both local development and production.
const API_URL = process.env.NODE_ENV === 'production' ? LIVE_BACKEND_URL : 'http://localhost:3001';

export const WEBSOCKET_URL = process.env.NODE_ENV === 'production'
  ? LIVE_BACKEND_URL.replace(/^http/, 'ws') // Converts http/https to ws/wss
  : 'ws://localhost:3001';

// We create an 'instance' of axios. This is a best practice for larger apps.
const api = axios.create({
  baseURL: API_URL,
});

// Axios interceptor: This function runs BEFORE any request is sent.
// It automatically attaches the user's authentication token to the headers.
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      // If a token exists, add it to the 'Authorization' header.
      // The 'Bearer ' prefix is a standard for JWTs.
      config.headers['Authorization'] = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    // If there's an error during the request setup, we reject the promise.
    return Promise.reject(error);
  }
);

export default api;
